Content file resources in AnalogJS 2.0 allow developers to retrieve content as reactive signals using Angular's latest primitives. For example, to display a list of posts, you can use `contentFilesResource` to load content dynamically. Here's a component example:
ts
import { Component } from '@angular/core';
import { contentFilesResource } from '@analogjs/content/resources';
import { PostsComponent } from '../../components/posts';
import { Post } from '../../data/posts';

@Component({
  selector: 'blog-posts',
  imports: [PostsComponent],
  template: `
    @defer(hydrate on hover) {
      <posts [posts]="postsResource.value()"></posts>
    }
  `
})
export default class Blog {
  readonly postsResource = contentFilesResource<Post>();
}

This approach integrates seamlessly with Angular's reactivity system.

To create a markdown blog post page in AnalogJS, you can use the `contentFileResource` to fetch the post data reactively. Here's an example:

ts
import { Component } from '@angular/core';
import { MarkdownComponent } from '@analogjs/content';
import { contentFileResource } from '@analogjs/content/resources';
import { RouteMeta } from '@analogjs/router';
import { Post } from '../../data/posts';
import { postMetaResolver, postTitleResolver } from './resolvers';

export const routeMeta: RouteMeta = {
  title: postTitleResolver,
  meta: postMetaResolver,
};

@Component({
  selector: 'post',
  imports: [MarkdownComponent],
  template: `
    @let post = postResource.value();
    @if (post) {
      <div class="flex flex-grow justify-center min-h-screen">
        <article class="w-screen max-w-4xl p-8">
          <h2 class="text-gray-600 text-2xl">{{ post.attributes.title }}</h2>
          <span class="font-light text-sm">
            {{ post.attributes.publishedDate }} - {{ post.content }} min read
          </span>
          <analog-markdown [content]="post.content"></analog-markdown>
        </article>
      </div>
    }
  `
})
export default class BlogPost {
  readonly postResource = contentFileResource<Post>();
}

This sets up a dynamic blog post page with markdown support, title resolution, and metadata handling.
